{
  "business_expectations": [
    {
      "id": "回答确认轻症多次赔付",
      "description": "用户询问轻症是否能够多次赔付，回答应明确肯定可以多次赔付",
      "acceptance_criteria": "回答中包含“轻症可以赔付多次”或等效表述"
    },
    {
      "id": "回答提供每次赔付金额比例",
      "description": "用户询问每次赔多少，回答应提供常见的赔付比例范围",
      "acceptance_criteria": "回答中包含基本保险金额的20%至30%或等效比例描述"
    },
    {
      "id": "赔付比例准确性",
      "description": "提供的比例应与行业常见标准一致，即20%-30%",
      "acceptance_criteria": "比例范围在20%至30%之间，无错误"
    },
    {
      "id": "提及次数上限示例",
      "description": "回答应提供可能的次数上限示例，以便用户了解常见限制",
      "acceptance_criteria": "回答中提及次数上限如3次或5次"
    },
    {
      "id": "提及间隔期要求",
      "description": "回答应提示多次赔付之间可能存在间隔期，避免用户误解可连续赔付",
      "acceptance_criteria": "回答中包含“间隔期要求”或等效表述"
    },
    {
      "id": "建议查阅具体合同",
