    },
    {
      "id": "回答与参考标准一致无矛盾",
      "description": "回答内容不应与标准参考答案产生事实性矛盾",
      "acceptance_criteria": "回答中的所有事实声明（比例、次数、间隔期）与参考答案一致，无矛盾"
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "回答确认轻症多次赔付",
